mapper.select:
SELECT n.POST_SN , n.NOTICE_TYPE_CD , b.POST_SJ , b.POST_CN , b.WRTR_USER_ID , b.TOP_FIX_ORD , b.POPUP_EXPS_YN , b.REG_DT , b.MDFCN_DT , c.COM_CD_NM AS NOTICE_TYPE_NM FROM NOTICE n JOIN BOARD b ON b.POST_SN = n.POST_SN LEFT JOIN COM_CD c ON c.CL_CODE = '103' AND c.COM_CD = n.NOTICE_TYPE_CD
AND n.NOTICE_TYPE_CD = #{noticeTypeCd}
ORDER BY b.TOP_FIX_ORD ASC NULLS LAST, b.REG_DT DESC

mapper.insert:
INSERT INTO NOTICE (
    POST_SN
    , NOTICE_TYPE_CD
) VALUES (
    #{postSn}
    , #{noticeTypeCd, jdbcType=CHAR}
)

mapper.update:
UPDATE NOTICE
SET NOTICE_TYPE_CD = #{noticeTypeCd, jdbcType=CHAR}
WHERE POST_SN = #{postSn}
